  72:                         measurements = snapshot.measurements.mapNotNull { record ->
  73:                             runCatching { RingMetricType.valueOf(record.metricType) }
  74:                                 .getOrNull()
  75:                                 ?.let { it to record }
  76:                         }.toMap(),
  77:                         sleep = snapshot.sleep,
  78:                         activity = snapshot.activity,
  79:                         signals = snapshot.signals.mapNotNull { record ->
  80:                             runCatching { RingMetricType.valueOf(record.signalType) }
  81:                                 .getOrNull()
