 119:     private suspend fun runAutoCollectionCycle() {
 120:         if (mutableUiState.value.isSyncing) return
 121:         Log.i(TAG, "auto collection cycle start")
 122:         mutableUiState.update {
 123:             it.copy(isSyncing = true, measuringMetric = null, syncProgress = 12, message = "姝ｅ湪鑷姩閲囬泦鎴掓寚鏁版嵁")
 124:         }
 125:         val totalRecords = runCatching {
 126:             var records = repository.syncAll().recordsWritten
 127:             listOf(
