 134:                     state.copy(
 135:                         measuringMetric = type,
 136:                         syncProgress = 30 + index * 15,
 137:                         message = "姝ｅ湪鑷姩閲囬泦${type.displayName()}",
 138:                     )
 139:                 }
 140:                 records += repository.measure(type).recordsWritten
 141:                 delay(800)
 142:             }
 143:             records
 144:         }
 145:         totalRecords
 146:             .onSuccess { records ->
